import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import './MeetingsScreen.css';

const MeetingsScreen = ({ config }) => {
  const [meetings, setMeetings] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [selectedMeeting, setSelectedMeeting] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [polling, setPolling] = useState(false);
  const [recording, setRecording] = useState(false);

  const mediaRecorderRef = useRef(null);

  const [form, setForm] = useState({
    meetingRoom: '',
    title: '',
    organizer: '',
    transcriptionEnabled: true
  });

  const [participants, setParticipants] = useState([
    { name: '', email: '' }
  ]);

  useEffect(() => {
    fetchMeetings();
  }, []);

  const fetchMeetings = async () => {
    try {
      const res = await axios.get('/meetings?limit=20');
      setMeetings(res.data.meetings || []);
    } catch (err) {
      console.error('Error fetching meetings:', err);
    }
  };

  const handleCreate = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const payloadParticipants = participants
        .filter(p => p.email && p.email.trim())
        .map(p => ({
          name: p.name?.trim() || '',
          email: p.email.trim(),
          role: 'participant'
        }));

      const res = await axios.post('/meetings', {
        meetingRoom: form.meetingRoom.trim(),
        title: form.title.trim(),
        organizer: form.organizer.trim(),
        participants: payloadParticipants,
        transcriptionEnabled: form.transcriptionEnabled
      });
      setSelectedMeeting(res.data.meeting);
      fetchMeetings();
    } catch (err) {
      console.error('Error creating meeting:', err);
      let serverError =
        err.response?.data?.error ||
        err.response?.data?.details ||
        err.message;
      if (err.message === 'Network Error') {
        serverError = 'Cannot reach workplace server. Please ensure the backend is running on port 5001.';
      }
      setError(serverError || 'Failed to create meeting');
    } finally {
      setLoading(false);
    }
  };

  const handleAudioUpload = async (e) => {
    if (!selectedMeeting) return;
    const file = e.target.files[0];
    if (!file) return;
    await uploadAudio(file);
  };

  const pollForSummary = async (id) => {
    let attempts = 0;
    const maxAttempts = 20;
    const interval = 5000;

    const poll = async () => {
      try {
        const res = await axios.get(`/meetings/${id}`);
        const m = res.data.meeting;
        setSelectedMeeting(m);
        if (m.transcriptionStatus === 'Completed' || m.transcriptionStatus === 'Failed' || attempts >= maxAttempts) {
          setPolling(false);
          return;
        }
        attempts += 1;
        setTimeout(poll, interval);
      } catch (err) {
        console.error('Error polling meeting summary:', err);
        setPolling(false);
      }
    };

    poll();
  };

  const companyName = config?.companyName || 'Your Company';

  const uploadAudio = async (fileOrBlob) => {
    if (!selectedMeeting) return;
    setUploading(true);
    setError('');

    try {
      const data = new FormData();
      // If we received a raw Blob (from MediaRecorder), wrap it in a File with a proper extension
      let fileToSend = fileOrBlob;
      if (fileOrBlob instanceof Blob && !(fileOrBlob instanceof File)) {
        fileToSend = new File([fileOrBlob], 'meeting-audio.webm', { type: 'audio/webm' });
      }

      data.append('audio', fileToSend);
      const res = await axios.post(`/meetings/${selectedMeeting._id}/end`, data, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      setSelectedMeeting(res.data.meeting);
      setUploading(false);
      setPolling(true);
      pollForSummary(res.data.meeting._id);
    } catch (err) {
      console.error('Error uploading audio:', err);
      let serverError =
        err.response?.data?.error ||
        err.response?.data?.details ||
        err.message;
      if (err.message === 'Network Error') {
        serverError = 'Cannot reach workplace server. Please ensure the backend is running on port 5001.';
      }
      setError(serverError || 'Failed to upload audio');
      setUploading(false);
    }
  };

  const startRecording = async () => {
    if (!selectedMeeting) {
      setError('Please select or create a meeting first.');
      return;
    }
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      const chunks = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          chunks.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const blob = new Blob(chunks, { type: 'audio/webm' });
        stream.getTracks().forEach(t => t.stop());
        await uploadAudio(blob);
      };

      mediaRecorderRef.current = mediaRecorder;
      mediaRecorder.start();
      setRecording(true);
      setError('');
    } catch (err) {
      console.error('Error starting recording:', err);
      setError('Unable to access microphone. Please check browser permissions.');
    }
  };

  const stopRecording = () => {
    const recorder = mediaRecorderRef.current;
    if (recorder && recorder.state !== 'inactive') {
      recorder.stop();
      setRecording(false);
    }
  };

  return (
    <div className="meetings-screen">
      <div className="meetings-wrapper">
        <div className="meetings-header">
          <h1 className="meetings-title">Meeting Assistant</h1>
          <p className="meetings-subtitle">
            Create meetings and upload audio recordings to generate AI-powered summaries.
          </p>
        </div>

        {error && <div className="error-message">{error}</div>}

        <div className="meetings-layout">
          <div className="meetings-left">
            <div className="card">
              <div className="card-header">
                <h2>New Meeting</h2>
              </div>
              <form onSubmit={handleCreate} className="meetings-form">
                <div className="form-group">
                  <label>Meeting Title</label>
                  <input
                    type="text"
                    value={form.title}
                    onChange={e => setForm({ ...form, title: e.target.value })}
                    placeholder={`Project review - ${companyName}`}
                    required
                  />
                </div>
                <div className="form-group">
                  <label>Meeting Room</label>
                  <input
                    type="text"
                    value={form.meetingRoom}
                    onChange={e => setForm({ ...form, meetingRoom: e.target.value })}
                    placeholder="e.g., Conference Room A"
                    required
                  />
                </div>
                <div className="form-group">
                  <label>Organizer</label>
                  <input
                    type="text"
                    value={form.organizer}
                    onChange={e => setForm({ ...form, organizer: e.target.value })}
                    placeholder="Organizer name or email"
                    required
                  />
                </div>
                <div className="form-group">
                  <label>Participants</label>
                  {participants.map((p, idx) => (
                    <div key={idx} className="participant-row">
                      <input
                        type="text"
                        placeholder="Name"
                        value={p.name}
                        onChange={e => {
                          const next = [...participants];
                          next[idx] = { ...next[idx], name: e.target.value };
                          setParticipants(next);
                        }}
                      />
                      <input
                        type="email"
                        placeholder="email@example.com"
                        value={p.email}
                        onChange={e => {
                          const next = [...participants];
                          next[idx] = { ...next[idx], email: e.target.value };
                          setParticipants(next);
                        }}
                      />
                      {participants.length > 1 && (
                        <button
                          type="button"
                          className="participant-remove"
                          onClick={() => {
                            setParticipants(participants.filter((_, i) => i !== idx));
                          }}
                        >
                          ×
                        </button>
                      )}
                    </div>
                  ))}
                  <button
                    type="button"
                    className="btn btn-secondary"
                    style={{ marginTop: '8px' }}
                    onClick={() => setParticipants([...participants, { name: '', email: '' }])}
                  >
                    Add Participant
                  </button>
                  <small>AI summaries will be emailed to these participants when ready (if email is configured).</small>
                </div>
                <div className="form-group-inline">
                  <label>
                    <input
                      type="checkbox"
                      checked={form.transcriptionEnabled}
                      onChange={e => setForm({ ...form, transcriptionEnabled: e.target.checked })}
                    />
                    <span> Enable AI meeting summary</span>
                  </label>
                </div>
                <button type="submit" className="btn btn-primary" disabled={loading}>
                  {loading ? 'Creating...' : 'Create Meeting'}
                </button>
              </form>
            </div>

            {selectedMeeting && (
              <div className="card">
                <div className="card-header">
                  <h2>Current Meeting</h2>
                </div>
                <div className="meeting-details">
                  <p><strong>Title:</strong> {selectedMeeting.title}</p>
                  <p><strong>Room:</strong> {selectedMeeting.meetingRoom}</p>
                  <p><strong>Status:</strong> {selectedMeeting.transcriptionStatus || selectedMeeting.status}</p>
                </div>

                <div className="form-group-inline">
                  {selectedMeeting.status === 'Scheduled' && (
                    <button
                      type="button"
                      className="btn btn-secondary"
                      onClick={async () => {
                        try {
                          const res = await axios.post(`/meetings/${selectedMeeting._id}/start`);
                          setSelectedMeeting(res.data.meeting);
                          fetchMeetings();
                        } catch (err) {
                          console.error('Error starting meeting:', err);
                          let serverError =
                            err.response?.data?.error ||
                            err.response?.data?.details ||
                            err.message;
                          setError(serverError || 'Failed to start meeting');
                        }
                      }}
                    >
                      Start Meeting
                    </button>
                  )}

                  {selectedMeeting.transcriptionEnabled && (
                    <>
                      <button
                        type="button"
                        className="btn btn-primary"
                        onClick={startRecording}
                        disabled={recording || uploading}
                        style={{ marginRight: '8px' }}
                      >
                        {recording ? 'Recording…' : 'Start Recording'}
                      </button>
                      <button
                        type="button"
                        className="btn btn-secondary"
                        onClick={stopRecording}
                        disabled={!recording || uploading}
                      >
                        Stop & Upload
                      </button>
                    </>
                  )}
                </div>

                {selectedMeeting.transcriptionEnabled && (
                  <div className="form-group">
                    <label>Or upload existing audio file</label>
                    <input
                      type="file"
                      accept="audio/*"
                      onChange={handleAudioUpload}
                      disabled={uploading}
                    />
                    <small>Use this if you already have a recording.</small>
                  </div>
                )}

                {polling && (
                  <p className="info-text">Processing transcription and summary…</p>
                )}
                {selectedMeeting.summary && (
                  <div className="summary-section">
                    <h3>AI Meeting Summary</h3>
                    <p className="summary-text">{selectedMeeting.summary}</p>
                    {!!(selectedMeeting.keyPoints || []).length && (
                      <>
                        <h4>Key Points</h4>
                        <ul>
                          {selectedMeeting.keyPoints.map((p, idx) => <li key={idx}>{p}</li>)}
                        </ul>
                      </>
                    )}
                  </div>
                )}
              </div>
            )}
          </div>

          <div className="meetings-right">
            <div className="card">
              <div className="card-header">
                <h2>Recent Meetings</h2>
              </div>
              <div className="meetings-list">
                {(meetings || []).length === 0 && (
                  <p className="info-text">No meetings created yet.</p>
                )}
                {(meetings || []).map(m => (
                  <div
                    key={m._id}
                    className={`meeting-item ${selectedMeeting && selectedMeeting._id === m._id ? 'active' : ''}`}
                    onClick={() => setSelectedMeeting(m)}
                  >
                    <div className="meeting-title">{m.title}</div>
                    <div className="meeting-meta">
                      <span>{m.meetingRoom}</span>
                      <span>{m.status}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
      <div className="branding-footer">
        Workplace Visitor Management System
      </div>
    </div>
  );
};

export default MeetingsScreen;
